    async validateFacebookAPI() {
        const issues = [];
        const config = this.apiConfigs.get('API_CONFIG_TEMPLATE') || {};
        
        // Check required credentials
        if (!config.FACEBOOK_APP_ID) {
            issues.push({
                type: 'missing_app_id',
                severity: 'high',
                autoFix: 'prompt_for_app_id'
            });
        }
        
        if (!config.FACEBOOK_APP_SECRET) {
            issues.push({
                type: 'missing_app_secret',
                severity: 'high',
                autoFix: 'prompt_for_app_secret'
            });
        }
        
        if (!config.FACEBOOK_ACCESS_TOKEN) {
            issues.push({
                type: 'missing_access_token',
                severity: 'high',
                autoFix: 'prompt_for_access_token'
            });
        }

        // Test API connectivity if credentials are present
        if (config.FACEBOOK_ACCESS_TOKEN) {
            try {
                const isValid = await this.testFacebookToken(config.FACEBOOK_ACCESS_TOKEN);
                if (!isValid) {
                    issues.push({
                        type: 'invalid_token',
                        severity: 'high',
                        autoFix: 'refresh_token'
                    });
                }
            } catch (error) {
                issues.push({
                    type: 'connection_failed',
                    severity: 'medium',
                    error: error.message,
                    autoFix: 'check_network_connectivity'
                });
            }
        }

        return {
            valid: issues.length === 0,
            issues,
            config: {
                hasAppId: !!config.FACEBOOK_APP_ID,
                hasAppSecret: !!config.FACEBOOK_APP_SECRET,
                hasAccessToken: !!config.FACEBOOK_ACCESS_TOKEN
            }
        };
    }

    async testFacebookToken(token) {
        return new Promise((resolve, reject) => {
            const options = {
                hostname: 'graph.facebook.com',
                path: `/me?access_token=${token}`,
                method: 'GET',
                timeout: this.timeoutMs
            };

            const req = https.request(options, (res) => {
                let data = '';
                res.on('data', chunk => data += chunk);
                res.on('end', () => {
                    if (res.statusCode === 200) {
                        resolve(true);
                    } else {
                        resolve(false);
                    }
                });
            });

            req.on('error', reject);
            req.on('timeout', () => {
                req.destroy();
                reject(new Error('Request timeout'));
            });

            req.end();
        });
    }

    async validateTelegramAPI() {
        const issues = [];
        const config = this.apiConfigs.get('API_CONFIG_TEMPLATE') || {};
        
        if (!config.TELEGRAM_BOT_TOKEN) {
            issues.push({
                type: 'missing_bot_token',
                severity: 'high',
                autoFix: 'prompt_for_bot_token'
            });
        }

        if (!config.TELEGRAM_CHAT_ID) {
            issues.push({
                type: 'missing_chat_id',
                severity: 'medium',
                autoFix: 'prompt_for_chat_id'
            });
        }

        // Test bot connectivity if token is present
        if (config.TELEGRAM_BOT_TOKEN) {
            try {
                const isValid = await this.testTelegramBot(config.TELEGRAM_BOT_TOKEN);
                if (!isValid) {
                    issues.push({
                        type: 'invalid_bot_token',
                        severity: 'high',
                        autoFix: 'regenerate_bot_token'
                    });
                }
            } catch (error) {
                issues.push({
                    type: 'bot_connection_failed',
                    severity: 'medium',
                    error: error.message,
                    autoFix: 'check_bot_permissions'
                });
            }
        }

        return {
            valid: issues.length === 0,
            issues,
            config: {
                hasBotToken: !!config.TELEGRAM_BOT_TOKEN,
                hasChatId: !!config.TELEGRAM_CHAT_ID
            }
        };
    }

    async testTelegramBot(token) {
        return new Promise((resolve, reject) => {
            const options = {
                hostname: 'api.telegram.org',
                path: `/bot${token}/getMe`,
                method: 'GET',
                timeout: this.timeoutMs
            };

            const req = https.request(options, (res) => {
                let data = '';
                res.on('data', chunk => data += chunk);
                res.on('end', () => {
                    try {
                        const response = JSON.parse(data);
                        resolve(response.ok);
                    } catch (error) {
                        reject(error);
                    }
                });
            });

            req.on('error', reject);
            req.on('timeout', () => {
                req.destroy();
                reject(new Error('Request timeout'));
            });

            req.end();
        });
    }

