    getValidationSummary() {
        const summary = {
            totalValidations: this.validationHistory.length,
            successfulValidations: this.validationHistory.filter(v => v.result.valid).length,
            failedValidations: this.validationHistory.filter(v => !v.result.valid).length,
            fixedValidations: this.validationHistory.filter(v => v.fixed).length,
            apis: {}
        };

        // Group by API
        for (const validation of this.validationHistory) {
            if (!summary.apis[validation.api]) {
                summary.apis[validation.api] = {
                    total: 0,
                    successful: 0,
                    failed: 0,
                    fixed: 0
                };
            }
            
            summary.apis[validation.api].total++;
            if (validation.result.valid) summary.apis[validation.api].successful++;
            if (!validation.result.valid) summary.apis[validation.api].failed++;
            if (validation.fixed) summary.apis[validation.api].fixed++;
        }

        return summary;
    }

